  if (signedLongs) {
    return Integer.MAX_VALUE;
  } else {
    return -1;
  }
}

// https://stackoverflow.com/questions/12772939/java-storing-two-ints-in-a-long
public static long pack(int high, int low) {
  return (((long) high) << 32) | (low & 0xffffffffL);
}

